insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'aichi' and m.slug = 'nagoya'), 'aichi-nagoya-welfare-taxi', '重度障害者福祉タクシー利用券・リフト付タクシー利用券の交付', '名古屋市では、市バスや地下鉄の利用が困難な重度の障害のある方（福祉特別乗車券の交付を受けていない方）を対象に、市と契約しているタクシーを利用できる「福祉タクシー利用券」または「リフト付タクシー利用券」を交付しています。福祉タクシー利用券は1枚上限500円で、一乗車につき上限5,000円まで利用可能とされ、リフト付タクシー利用券は1枚上限2,000円で一乗車上限10,000円とされています。年間の交付枚数上限については、公式サイト内でも情報源により160枚程度とする記載と180枚程度とする記載が見られ、確認日時点で正確な最新の枚数を一つに絞り込めませんでした。両利用券は選択制で、どちらか一方を選んで利用する制度です。名古屋市には障害者向けの自動車燃料費助成制度は確認できませんでした。', '重い障害のある方が、名古屋市と契約しているタクシーに乗るときに使える「タクシー利用券」をもらえる制度です。普通のタクシー用と、車いすのまま乗れるリフト付タクシー用の2種類があり、どちらか一方を選びます。年間にもらえる枚数は区役所で確認するのが確実です。', 'service', '身体障害者手帳1・2級、療育手帳1・2度、身体障害者手帳3級かつ療育手帳3度、精神障害者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります（福祉タクシー利用券の場合）。リフト付タクシー利用券は、身体障害者手帳1・2級所持者のうち外出時に車いすやストレッチャーを使用する方が対象とされています。', '福祉タクシー利用券：1枚上限500円、一乗車上限5,000円。リフト付タクシー利用券：1枚上限2,000円、一乗車上限10,000円。年間交付枚数の上限は情報源により160枚（人工透析患者200枚）とする記載と、180枚（同220枚）とする記載があり、確認日時点で一致しませんでした。正確な最新の年間上限枚数は区役所または名古屋市障害企画課にご確認ください。', '随時受付とみられますが、交付枚数は申請月により異なるとされています。', '区役所福祉課（社会福祉事務所）または支所区民福祉課で申請します。継続（更新）交付についてはオンライン申請（電子申請システム）が可能とされていますが、新規交付はオンライン不可とみられます。', '申請書、身体障害者手帳・療育手帳・精神障害者保健福祉手帳など。有料道路通行料金、駐車料金、ストレッチャー等の使用料、介助料金等は助成の対象外とされています。', TRUE, '健康福祉局 障害福祉部 障害企画課 福祉担当', '052-972-2587', 'https://www.kaigo-wel.city.nagoya.jp/view/wel/service/denshi/taxi.html', 'https://www.city.nagoya.jp/kenkofukushi/shougaisha/1016573/1016575.html', 'タクシー料金の助成｜名古屋市公式ウェブサイト', '2026-07-01', 'medium', ARRAY['benefitAmountText（年間交付枚数の正確な上限）', 'requiredDocumentsText']::text[], '本情報は名古屋市公式サイトおよび名古屋市の情報提供システム（確認日時点）に基づく概要です。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があり、情報源間で年間交付枚数の記載に相違が見られました。受給を確約するものではなく、対象可否や最新の取扱いは必ず名古屋市の公式ページまたは区役所福祉課にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
