insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"aichi-nagoya-welfare-taxi","status":"review","title":"重度障害者福祉タクシー利用券・リフト付タクシー利用券の交付","officialUrl":"https://www.city.nagoya.jp/kenkofukushi/shougaisha/1016573/1016575.html","topic":"welfare-taxi"}'::jsonb, 'seirei:aichi-nagoya-welfare-taxi:YWljaGktbmFnb3lhLXdlbGZhcmUtdGF4aXxDVmpRZHhYMjVlTmw3MUNRYW4rUlJvWks=' from public.support_programs sp where sp.slug='aichi-nagoya-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'chiba' and m.slug = 'chiba'), 'chiba-chiba-welfare-taxi', '福祉タクシー事業・自動車燃料費等助成事業', '千葉市では、重度の障害のある方等の外出・通院を支えるため、市が指定するタクシー事業者を利用できる福祉タクシー利用券を交付する「福祉タクシー事業」と、自動車を使用する方を対象に燃料費の一部を助成する「自動車燃料費等助成事業」が設けられています。両事業はいずれか一方を選択して利用する制度で、同時に受給することはできないとされています。福祉タクシー利用券は年間30枚が交付され、利用期間は8月1日から翌年7月31日までとされ、一般タクシーでは1回の乗車につき2,600円以内は半額、超過時は1,300円の割引、リフト付タクシーでは11,000円以内は半額、超過時は5,500円の割引が適用されるとされています。対象者には所得制限が設けられており、特別障害者手当の所得制限限度額を超える場合は対象外とされています。詳細・最新の取扱いは千葉市の公式ページまたは担当窓口にご確認ください。', '重い障害のある方が外出やタクシーでの通院に使える「福祉タクシー券」（年間30枚）を千葉市が交付する制度です。自動車を使う方には、かわりにガソリン代の一部を助成する制度もあり、どちらか一方を選んで利用します。所得が高い場合は対象外になることがあります。', 'service', '身体障害者手帳1級・2級、療育手帳の重度区分（○A〜Aの2）、精神障害者保健福祉手帳1級の所持者や、特別児童扶養手当1級・障害児福祉手当・特別障害者手当の受給者、小児慢性特定疾病の重症患者などが対象となる可能性があります。ただし特別障害者手当の所得制限限度額を超える場合は対象外とされています。', '福祉タクシー利用券は年間30枚交付。利用期間は8月1日〜翌年7月31日。1回の利用につき、一般タクシーは運賃2,600円以内なら半額・超過時は1,300円割引、リフト付タクシーは運賃11,000円以内なら半額・超過時は5,500円割引とされています。自動車燃料費等助成は年額の助成金が複数回に分けて振り込まれるとされていますが、正確な金額は公式ページまたは窓口で確認することを推奨します。', NULL, '申請書（福祉タクシー：様式第7号、自動車燃料費等助成：様式第1号）に必要事項を記入し、対象となる障害の種別に応じた窓口（区保健福祉センター高齢障害支援課または健康課）へ提出するとされています。', '所定の申請書のほか、障害者手帳等の確認書類が必要になる可能性があります。具体的な必要書類は障害の種別や個々の状況により異なる場合があります。', FALSE, '千葉市保健福祉局高齢障害部障害者自立支援課（申請窓口は各区保健福祉センター高齢障害支援課または健康課）', '043-245-5173', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/jiritsu/hukushitakusi.html', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/jiritsu/hukushitakusi.html', '千葉市：福祉タクシー・自動車燃料費等助成事業のご案内', '2026-07-01', 'medium', ARRAY['benefitAmountText（自動車燃料費等助成の年間合計額・期別内訳）', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は千葉市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成額・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず千葉市の公式ページまたは担当窓口にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
