insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"chiba-chiba-welfare-taxi","status":"review","title":"福祉タクシー事業・自動車燃料費等助成事業","officialUrl":"https://www.city.chiba.jp/hokenfukushi/koreishogai/jiritsu/hukushitakusi.html","topic":"welfare-taxi"}'::jsonb, 'seirei:chiba-chiba-welfare-taxi:Y2hpYmEtY2hpYmEtd2VsZmFyZS10YXhpfEhCSWVOeDZ4L3FhaUpkSzJ6TVJ5cXpoWQ==' from public.support_programs sp where sp.slug='chiba-chiba-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'fukuoka'), 'fukuoka-fukuoka-welfare-taxi', '福祉タクシー料金助成事業', '福岡市では、重度の障がいのある方の外出を支えるため、市内のタクシー事業者と契約した福祉タクシー利用券を交付する「福祉タクシー料金助成事業」を実施しています。対象は、視覚障がい1・2級、下肢・体幹機能障がいまたは非進行性の脳病変による運動機能障がい1・2級、内部障がい1・2級、重複障がいで総合2級以上かつ下肢または体幹機能障がい3級、療育手帳A、精神障害者保健福祉手帳1級のいずれかに該当し、福岡市内に実際に居住し、18歳以上の場合は本人・配偶者ともに市民税非課税であることなど複数の要件を満たす方となる可能性があります。一般車タクシー用の利用券（1枚500円）は年間最大55枚、車いす等に対応するワゴン型タクシー用の利用券は年間最大48枚交付されるとされています。福岡市公式サイト上では、他自治体にみられるような『自動車燃料費助成』との選択制は確認できず、本制度は福祉乗車券・高齢者乗車券・障がい者移送サービスのタクシー助成券との選択制（併用不可）となっている点にご注意ください。', '重い障がいのある方が外出するときに使える「福祉タクシー利用券」を、福岡市がお渡しする制度です。1枚500円の券が年間最大55枚（または車いす用ワゴン車向けの券が年間最大48枚）交付される可能性があります。福祉乗車券などほかの乗車券制度とは、どちらか一方を選んで利用する仕組みになっています。', 'service', '福岡市内に実際に居住し、視覚障がい1級・2級、下肢・体幹機能障がいまたは乳幼児期以前の非進行性脳病変による運動機能障がい1級・2級、内部障がい1級・2級、重複障がいで総合2級以上かつ下肢または体幹機能障がい3級、療育手帳A、精神障害者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります。18歳以上の場合は本人および配偶者がともに市民税非課税であることも要件とされています。施設に入所している方および入院中の方は対象外とされています。', '一般車タクシー利用券：1枚500円、年間最大55枚（4・5月申請時）。ワゴン型タクシー利用券：30分までの時間制運賃額相当、年間最大48枚（4・5月申請時）。申請時期により交付枚数が異なる可能性があります。', NULL, '居住する区の福祉・介護保険課または健康課の窓口で申請するか、必要書類を福岡市行政事務センターへ郵送して申請する方法があるとされています。代理人が申請する場合は委任状の提出および代理人の身分証明書の提示が必要とされています。', '障害者手帳（代理申請の場合は委任状および代理人の身分証明書）', FALSE, '各区福祉・介護保険課／健康課（福岡市福祉局障がい者在宅支援課）', '092-718-1100', NULL, 'https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/taxi_8_1.html', '令和8年度福祉タクシー料金助成事業について - 福岡市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'contactPhone']::text[], '本情報は福岡市公式サイト（確認日時点、令和8年度版ページ）に基づく概要です。対象要件・交付額・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず福岡市の公式ページまたは担当窓口にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
