insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"fukuoka-fukuoka-welfare-taxi","status":"review","title":"福祉タクシー料金助成事業","officialUrl":"https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/taxi_8_1.html","topic":"welfare-taxi"}'::jsonb, 'seirei:fukuoka-fukuoka-welfare-taxi:ZnVrdW9rYS1mdWt1b2thLXdlbGZhcmUtdGF4aXx5U05GcHdHcEt4amtLMjkyVVZwWHo4M2w=' from public.support_programs sp where sp.slug='fukuoka-fukuoka-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'fukuoka' and m.slug = 'kitakyushu'), 'fukuoka-kitakyushu-welfare-taxi', '重度障害者に対するタクシー運賃の一部助成（重度障害者タクシー利用券）', '北九州市では、在宅の重度障害のある方が外出等の手段としてタクシーを利用する場合に、乗車運賃の一部を助成する「重度障害者タクシー利用券」を交付しています。対象となるのは、市民税非課税世帯で市内に住所を有し、視覚障害・肢体不自由（下肢・体幹・移動機能）・内部障害で身体障害者手帳1・2級（複数障害の合併による1・2級を除く）、療育手帳「A」、または精神障害者保健福祉手帳1級のいずれかに該当する在宅の方とされています。助成回数は年間最大48回までとされ、タクシー乗車時に該当する手帳を提示のうえ利用券を乗務員に渡す方式です。利用できるのは北九州タクシー協会加入のタクシー会社および市と契約したタクシーとされています。なお、自動車を利用する方向けの燃料費助成については、公式ガイドブックの該当章を確認した限り北九州市独自の制度としては見当たりませんでした。', '重い障害のある方がタクシーで外出するときに使える「タクシー利用券」を、北九州市がお渡しする制度です。手帳を見せてタクシーの運転手さんに券を渡すと、運賃の一部が助成されます。1年間に使える回数の上限があります。', 'service', '市民税非課税世帯で北九州市内に住所を有する在宅の方のうち、次のいずれかに該当する可能性があります。(1)視覚障害・肢体不自由（下肢・体幹・移動機能障害）・内部障害で身体障害者手帳1・2級（複数障害の合併による1・2級は対象外）、(2)療育手帳「A」、(3)精神障害者保健福祉手帳1級。施設入所中または退院見込みのない入院中の方は対象外とされています。', 'タクシー普通車の初乗運賃相当額の利用券（年間最大48回まで）。電動車椅子利用者は電動車椅子用タクシーの初乗運賃相当額の利用券が交付されるとされています。', NULL, '障害者手帳、世帯全員分の印鑑または本人確認書類、通知書（代理人申請の場合は委任状も必要）を持参し、各区役所「高齢者・障害者相談コーナー」で申請するとされています。オンライン申請の様式は公式サイト上では確認できませんでした。', '対象となる障害者手帳、世帯全員分の印鑑または本人確認書類、通知書。代理人による申請の場合は委任状も必要とされています。', FALSE, '北九州市 各区役所 高齢者・障害者相談コーナー', '', NULL, 'https://www.city.kitakyushu.lg.jp/contents/17600232.html', '障害福祉ガイド（令和7年度版）－北九州市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'contactPhone', '月あたりの交付枚数の詳細']::text[], '本情報は北九州市公式サイト掲載の「障害福祉ガイド（令和7年度版、令和7年4月現在）」に基づく概要です。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず北九州市の公式ページまたは各区役所高齢者・障害者相談コーナーにご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
