insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"fukuoka-kitakyushu-welfare-taxi","status":"review","title":"重度障害者に対するタクシー運賃の一部助成（重度障害者タクシー利用券）","officialUrl":"https://www.city.kitakyushu.lg.jp/contents/17600232.html","topic":"welfare-taxi"}'::jsonb, 'seirei:fukuoka-kitakyushu-welfare-taxi:ZnVrdW9rYS1raXRha3l1c2h1LXdlbGZhcmUtdGF4aXxOT2lGa2JOMFJ6b2NmbTMvZkJoUlpQbEI=' from public.support_programs sp where sp.slug='fukuoka-kitakyushu-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hiroshima' and m.slug = 'hiroshima'), 'hiroshima-hiroshima-welfare-taxi', '重度障害者福祉タクシー利用助成', '広島市では、重度の障害のある方の社会参加や外出を支えるため、市と契約しているタクシー事業者で利用できる「福祉タクシー乗車券」を交付する重度障害者福祉タクシー利用助成を実施しています。対象となるのは、身体障害者手帳（視覚障害1〜2級、肢体不自由第1種、内部障害1〜2級等）、療育手帳（マルA・A）、精神障害者保健福祉手帳（1級）のいずれかを所持し、かつ前年の所得が一定基準以下の方とされています。交付されるのは1年間（9月1日から翌年8月31日まで）に1枚あたり500円を限度とする乗車券で、身体・療育手帳所持者は52枚、精神障害者保健福祉手帳所持者は58枚が上限とされています。なお、広島市には自動車利用者向けの燃料費助成という別制度は公式サイト上で確認できず、本制度は同じく交通助成である「障害者公共交通機関利用助成（いきいき乗車券）」とのいずれか一方の選択制となっている点に注意が必要です。', '重い障害のある方が、タクシーで通院や外出をするときに使える「タクシー券」を広島市がお渡しする制度です。1年間に52枚（精神障害の方は58枚）、1枚500円分まで使えます。似た制度の「いきいき乗車券」とはどちらか一方しか選べません。', 'service', '広島市内に住み、前年の所得が一定基準額以下であることに加え、次のいずれかに該当する方が対象となる可能性があります。(1)身体障害者手帳所持者で視覚障害1〜2級、肢体不自由第1種、心臓・腎臓・呼吸器等の内部障害1〜2級、または補装具として車いすの交付を受けている方、(2)療育手帳「マルA」「A」判定の方、(3)精神障害者保健福祉手帳1級所持者。ただし、障害者公共交通機関利用助成（いきいき乗車券）の交付を受けている方は対象外とされ、いずれか一方の選択制です。', '1年間（9月1日〜翌年8月31日）に、1枚あたり500円を限度額とする福祉タクシー乗車券を交付。身体障害者手帳・療育手帳所持者は52枚を限度、精神障害者保健福祉手帳所持者は58枚を限度。', '随時ではなく、広島市から対象者へ申請書が郵送される方式です。公式ページによれば例年6月中旬と10月頃に申請書が発送されるとされていますが、正確な時期は年度により変わる可能性があります。', '広島市から対象と見込まれる方へ申請書が郵送され、申請後に所得確認等を経て決定通知と利用券が郵送されるという流れです。', '公式ページ本文には具体的な必要書類の一覧が明記されていないため不明です。障害者手帳の提示や所得を確認できる書類が必要になる可能性がありますが、詳細は窓口にご確認ください。', FALSE, '広島市健康福祉局障害福祉部障害福祉課（精神障害者保健福祉手帳の方は精神保健福祉課）', '082-504-2147', NULL, 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014921/1025788/1022075.html', '重度障害者福祉タクシー利用助成｜広島市公式ウェブサイト', '2026-07-01', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText', '腎臓透析治療者への追加交付枚数の詳細']::text[], '本情報は広島市公式サイト（確認日時点）に基づく概要です。対象要件・交付額・年間限度額・必要書類・申請時期などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず広島市の公式ページまたは担当窓口にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
