insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"hiroshima-hiroshima-welfare-taxi","status":"published","title":"重度障害者福祉タクシー利用助成","officialUrl":"https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014921/1025788/1022075.html","topic":"welfare-taxi"}'::jsonb, 'seirei:hiroshima-hiroshima-welfare-taxi:aGlyb3NoaW1hLWhpcm9zaGltYS13ZWxmYXJlLXRheGl8U2NHR0lrTEw5RTgwdlZybncwWXBaeXBa' from public.support_programs sp where sp.slug='hiroshima-hiroshima-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hokkaido' and m.slug = 'sapporo'), 'hokkaido-sapporo-welfare-taxi', '障がい者交通費助成（福祉タクシー利用券・福祉自動車燃料助成券）', '札幌市では、身体障がい・知的障がい・精神障がいのある方等の社会参加を促すため、交通費の一部を助成する「障がい者交通費助成」を実施しています。対象者は、市が委託するタクシーで利用できる「福祉タクシー利用券」（1枚500円）、自動車の燃料代にあてられる「福祉自動車燃料助成券」（1枚1,000円）、またはサピカ（ICカード乗車券）へのチャージのいずれかを選択して利用する仕組みとされています。助成される年間上限額は障がいの程度によって異なり、身体障がい1・2級、知的障がいA、精神障がい1・2級の方はタクシー券で年間最大39,000円または燃料券で年間最大30,000円、身体障がい3・4級、知的障がいB、精神障がい3級の方はタクシー券・燃料券とも年間最大13,000円・10,000円程度となる可能性があります。申請は各区役所保健福祉課の窓口で受け付けており、オンライン申請の記載は確認できませんでした。介護保険制度における「介護タクシー」（通院等乗降介助）とは異なる、障がい福祉分野の制度です。', '札幌市に住む障がいのある方が、タクシーを利用するときや自動車の燃料代がかかるときに使える金券を交付してもらえる制度です。障がいの種類や程度によって、もらえる金額の上限が変わります。窓口は区役所の保健福祉課です。', 'service', '身体障害者手帳（1〜4級）、療育手帳（A・B）、精神障害者保健福祉手帳（1〜3級）のいずれかをお持ちの方が対象となる可能性があります。このほか、戦傷病者手帳、いつくしみの手帳、被爆者健康手帳の交付を受けている方の一部や、東日本大震災の避難者も対象に含まれる場合があるとされています。等級によって助成の枠組みが異なるため、詳細な対象要件は公式ページまたは区役所窓口で確認してください。', '福祉タクシー利用券は1枚500円、福祉自動車燃料助成券は1枚1,000円で交付されるとされています。年間上限額は障がいの程度により異なり、身体障がい1・2級・知的障がいA・精神障がい1・2級の方はタクシー券で年間最大39,000円、燃料券で年間最大30,000円、身体障がい3・4級・知的障がいBの方等はタクシー券・燃料券とも年間最大13,000円・10,000円程度となる可能性があります。正確な等級区分・上限額は公式ページまたは区役所窓口で必ず確認してください。', NULL, '各区役所保健福祉課給付事務係の窓口で申請するとされています。サピカへのチャージ申請については、札幌市役所障がい福祉課でも申請できる場合があるとされています。オンライン申請についての記載は公式ページ上に見当たりませんでした。', '各種手帳（身体障害者手帳・療育手帳・精神障害者保健福祉手帳等）、既に福祉乗車証を利用している場合はその福祉乗車証、燃料券を申請する場合は車検証（写し可）、サピカへのチャージを希望する場合は記名サピカまたは福祉割引サピカ、代理申請の場合は代理人の氏名確認書類が必要とされています。', FALSE, '札幌市保健福祉局障がい保健福祉部障がい福祉課（申請窓口は各区役所保健福祉課給付事務係）', '011-211-2936', 'https://www.city.sapporo.jp/shogaifukushi/kotsuhi/index.html', 'https://www.city.sapporo.jp/shogaifukushi/kotsuhi/index.html', '障がい者交通費助成／札幌市', '2026-07-01', 'medium', ARRAY['benefitAmountText（等級ごとの上限額区分に情報源間で表記の揺れ）', 'applicationDeadlineText', 'onlineApplicationAvailable']::text[], '本情報は札幌市公式サイト（確認日時点）に基づく概要です。対象要件・交付額・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず札幌市の公式ページまたは各区役所保健福祉課にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
