insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"hokkaido-sapporo-welfare-taxi","status":"review","title":"障がい者交通費助成（福祉タクシー利用券・福祉自動車燃料助成券）","officialUrl":"https://www.city.sapporo.jp/shogaifukushi/kotsuhi/index.html","topic":"welfare-taxi"}'::jsonb, 'seirei:hokkaido-sapporo-welfare-taxi:aG9ra2FpZG8tc2FwcG9yby13ZWxmYXJlLXRheGl8RThuMEhDMjVQN2VPWGM3bUhLcmNyRjVa' from public.support_programs sp where sp.slug='hokkaido-sapporo-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'hyogo' and m.slug = 'kobe'), 'hyogo-kobe-welfare-taxi', '重度心身障害者タクシー利用券助成・自動車燃料費助成（選択制）', '神戸市では、重い心身障害のある方の外出を支えるため、市と契約するタクシー事業者で利用できる「重度心身障害者タクシー利用券」の助成と、自動車を利用する方向けの「自動車燃料費助成」を実施しており、いずれか一方を選択して利用する制度です（両方の同時受給は不可）。タクシー利用券は1枚500円で、1年度で最大72枚交付され、1回の乗車で最大3枚まで使用可能とされています。自動車燃料費助成は、ガソリン・軽油・LPGが対象で、1年度で最大12,000円が助成されるとされ、申請時期により上限額が異なります。対象者は身体障害者手帳（視覚・下肢・体幹・移動機能・内部機能の障害等級や指数に基づく）、療育手帳A判定、精神障害者保健福祉手帳1級のいずれかに該当する方とされ、両制度とも同一の対象者要件が適用されるとみられます。', '重い障害のある方向けに、神戸市と契約したタクシーで使える「タクシー利用券」（1枚500円、年間最大72枚）と、車を使う方向けの「ガソリン代の助成」（年間最大12,000円）のどちらか一方を選んで利用できる制度です。両方同時にはもらえません。', 'service', '神戸市内に住んでいて、福祉乗車証・敬老優待乗車証を受けておらず、身体障害者手帳（視覚・下肢・体幹・移動機能・内部のいずれかが単独で1級または2級、または下肢・体幹・移動機能のいずれかが3級以上かつ上肢が4級以上、または複数部位の障害指数合計が11点以上）、療育手帳A判定、精神障害者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります。', 'タクシー利用券：1枚500円、1年度で最大72枚（1回の乗車で最大3枚まで使用可）。自動車燃料費助成：1年度で最大12,000円（申請時期により上限額が異なる）。両制度は選択制で、いずれか一方のみ利用可能です。', '有効期間は4月1日から翌年3月31日で、年度ごとの更新が必要とされています。交付枚数・助成上限額は申請時期により異なるとされています。', '初回申請は区役所窓口で行います。燃料費助成の請求は郵送またはe-KOBE（神戸市スマート申請システム）から年1回行うとされています。', '申請書、障害者手帳（身体障害者手帳・療育手帳・精神障害者保健福祉手帳のいずれか）。代理人が手続きする場合は代理人の本人確認書類が必要とされています。', TRUE, '神戸市行政事務センター「タクシー利用券助成」「自動車燃料費助成」担当（神戸市福祉局障害福祉課）', '078-647-8585', 'https://www.city.kobe.lg.jp/a97737/kenko/handicap/zaitakufukushi/koutsukikan/koutu.html', 'https://www.city.kobe.lg.jp/a40792/kenko/handicap/zaitakufukushi/koutsukikan/s031.html', '重度心身障害者タクシー利用券助成 - 神戸市', '2026-07-01', 'high', ARRAY['requiredDocumentsText']::text[], '本情報は神戸市公式サイト（タクシー利用券助成ページ、自動車燃料費助成ページおよび対象者詳細ページ、確認日時点）に基づく概要です。対象要件・交付枚数・年間限度額・燃料費助成額などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず神戸市の公式ページまたは神戸市行政事務センターにご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
