insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'kawasaki'), 'kanagawa-kawasaki-welfare-taxi', '川崎市福祉タクシー利用券（重度障害者福祉タクシー利用券交付事業）', '川崎市では、重度の障害のある方等の外出を支えるため、市と契約しているタクシー事業者で利用できる福祉タクシー利用券を交付しています。1人あたり月7枚（週3回以上人工透析で通院している腎臓機能障害の方は月14枚）が交付され、利用券1枚あたりの助成限度額は500円までとされています。1回の乗車で複数枚を組み合わせて使用することも可能とされています。なお、川崎市の公式サイトを確認した範囲では、自動車を利用する方向けの燃料費助成に相当する制度は見当たらず、タクシー利用券のみが実施されているとみられます。', '重い障害のある方が、川崎市と契約したタクシーに乗るときに使える「福祉タクシー利用券」を、市がお渡しする制度です。1か月に7枚（人工透析に通っている方は14枚）もらえるとされ、1枚につき500円分まで使えます。', 'service', '身体障害者手帳1級・2級（下肢・体幹・視覚・内部障害のいずれかを含む方）、療育手帳A1・A2、身体障害者手帳3級（下肢・体幹・視覚・内部障害のいずれかを含む方）かつ療育手帳B1、精神障害者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります。', '月7枚交付（1枚あたり助成限度額500円）。週3回以上人工透析で通院している腎臓機能障害の方は月14枚とされています。', NULL, '居住する区の区役所高齢・障害課の窓口で申請するとされています。', '身体障害者手帳・療育手帳・精神障害者保健福祉手帳のいずれか、印鑑、川崎市重度障害者福祉タクシー利用券交付申請書兼記載事項変更届、（更新の場合は）有効期限切れの既交付券。', FALSE, '健康福祉局障害者社会参加・就労支援課', '044-200-2928', NULL, 'https://www.city.kawasaki.jp/350/page/0000025652.html', '川崎市 : 川崎市福祉タクシー利用券', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable']::text[], '本情報は川崎市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず川崎市の公式ページまたは担当窓口（区役所高齢・障害課）にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
