insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"kanagawa-kawasaki-welfare-taxi","status":"published","title":"川崎市福祉タクシー利用券（重度障害者福祉タクシー利用券交付事業）","officialUrl":"https://www.city.kawasaki.jp/350/page/0000025652.html","topic":"welfare-taxi"}'::jsonb, 'seirei:kanagawa-kawasaki-welfare-taxi:a2FuYWdhd2Eta2F3YXNha2ktd2VsZmFyZS10YXhpfEIxWlhUeDJDUUp1VkFBNDQxdXg4Y3hCNw==' from public.support_programs sp where sp.slug='kanagawa-kawasaki-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'sagamihara'), 'kanagawa-sagamihara-welfare-taxi', '福祉タクシー利用助成・自動車燃料費助成（相模原市）', '相模原市では、重度の障害のある方や指定難病の方等の外出を支えるため、市と協定を締結したタクシー事業者で利用できる福祉タクシー利用券（1枚500円、申請月から3月分までの月数に月6枚を乗じた枚数を交付）を交付しています。あわせて、自動車を利用する方を対象とした自動車燃料費助成（本人運転は月2枚、他者運転は月1枚、1枚1,000円の給油券）も設けられており、公式ページでは「いずれかの制度を選択してください」と明記され、両制度は選択制で併給できないとされています。', '重い障害のある方や難病の方が、相模原市と提携したタクシーに乗るときに使える「福祉タクシー利用券」を市がお渡しする制度です。車を使う方には、かわりにガソリン代の助成券を渡す制度もあり、どちらか一方を選んで利用します。', 'service', '身体障害者手帳1級・2級、療育手帳A1・A2、知能指数35以下、特定医療費（指定難病）医療受給者証所持者、神奈川県特定疾患医療受給者証所持者、小児慢性特定疾病医療受給者証所持者、精神障害者保健福祉手帳1級・2級のいずれかに該当する在宅の方が対象となる可能性があります。施設入所者は対象外とされています。', '福祉タクシー利用券：1枚500円、申請月から3月分までの月数×月6枚を交付。自動車燃料費助成：1枚1,000円の給油券、本人運転は申請月から3月分までの月数×月2枚、他者運転は同×月1枚。', '随時受付とみられますが、交付枚数は申請月に応じて変動するとされています。', '各区の高齢・障害者相談課、保健センター、福祉相談センターの窓口で申請。', '福祉タクシー利用助成：対象区分に応じた手帳または受給者証の原本。自動車燃料費助成：該当する手帳または受給者証、自動車検査証、使用者が本人でない場合は実際の使用者を特定できる書類。', FALSE, '高齢・障害者支援課障害支援班', '042-769-8355', NULL, 'https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026641/shogai/jidosha/1006479.html', '福祉タクシー利用助成｜相模原市', '2026-07-01', 'high', ARRAY['applicationDeadlineText']::text[], '本情報は相模原市公式サイト（確認日時点）に基づく概要です。対象要件・交付額・年間限度額・燃料費助成額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず相模原市の公式ページまたは担当窓口（高齢・障害者支援課）にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
