insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"kanagawa-sagamihara-welfare-taxi","status":"published","title":"福祉タクシー利用助成・自動車燃料費助成（相模原市）","officialUrl":"https://www.city.sagamihara.kanagawa.jp/kosodate/fukushi/1026641/shogai/jidosha/1006479.html","topic":"welfare-taxi"}'::jsonb, 'seirei:kanagawa-sagamihara-welfare-taxi:a2FuYWdhd2Etc2FnYW1paGFyYS13ZWxmYXJlLXRheGl8ZEZBOUFmczhVSGtNZENOU1RwbmI0VGRX' from public.support_programs sp where sp.slug='kanagawa-sagamihara-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kanagawa' and m.slug = 'yokohama'), 'kanagawa-yokohama-welfare-taxi', '福祉タクシー利用券・障害者自動車燃料券の交付', '横浜市では、重度の障害のある方等の外出・通院を支えるため、市と契約するタクシー事業者で利用できる福祉タクシー利用券を交付しています。あわせて、自動車を利用する方を対象に、燃料費の一部を助成する障害者自動車燃料券も設けられており、福祉特別乗車券（バス・地下鉄等の福祉パス）を含めたこれら3制度はいずれか一つを選択して利用する仕組みとされています。福祉タクシー利用券は1枚500円を上限に、障害者自動車燃料券は1枚1,000円を限度に、それぞれ助成されるとされています。', '障害のある方がタクシーで出かけるときに使える「福祉タクシー利用券」を、横浜市がお渡しする制度です。車を使う方には、かわりにガソリン代などの燃料費を助成する「障害者自動車燃料券」もあり、バスや地下鉄用の福祉パスも含め、どれか一つを選んで利用します。', 'service', '身体障害者手帳（下肢・体幹・視覚・内部・移動機能障害のいずれかを含む1・2級、または一定条件を満たす3級等）、愛の手帳（療育手帳）A1・A2（燃料券はB2まで対象となる場合あり）、精神障害者保健福祉手帳1級（燃料券は1〜3級）等をお持ちの方が対象となる可能性があります。手帳の種類・等級により福祉タクシー利用券と障害者自動車燃料券とで対象範囲が異なるとされているため、詳細は公式ページまたは区福祉保健センターでの確認が必要です。', '福祉タクシー利用券：1枚につき500円を上限に助成。10月1日〜翌年9月30日の年間で84枚（人工透析で週3回以上通院の方は168枚）を交付、1回の乗車につき7枚まで利用可能とされています。障害者自動車燃料券：1枚につき1,000円を限度に助成。同じく年間で24枚（人工透析で週3回以上通院の方は48枚）を交付するとされています。', NULL, '手帳を持参のうえ、お住まいの区の福祉保健センターの窓口で申請するとされています。燃料券の場合は登録する自動車の自動車検査証の写しもあわせて必要とされています。', '身体障害者手帳・愛の手帳（療育手帳）・精神障害者保健福祉手帳のいずれか。障害者自動車燃料券の場合は、これに加えて登録する自動車の自動車検査証の写しが必要とされています。', FALSE, '健康福祉局障害福祉保健部障害自立支援課移動支援係', '045-671-2401', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/fukushi-kaigo/fukushi/annai/gaishutsu/kotsu/riyoken.html', 'https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/fukushi-kaigo/fukushi/annai/gaishutsu/kotsu/riyoken.html', '福祉タクシー利用券の交付 - 横浜市', '2026-07-01', 'high', ARRAY['愛の手帳B1・B2や3級身体障害者手帳の細かい併用条件', '申請期限の具体的な日付', 'オンライン申請の可否']::text[], '本情報は横浜市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成額・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず横浜市の公式ページまたはお住まいの区福祉保健センターにご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
