insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"kanagawa-yokohama-welfare-taxi","status":"review","title":"福祉タクシー利用券・障害者自動車燃料券の交付","officialUrl":"https://www.city.yokohama.lg.jp/kenko-iryo-fukushi/fukushi-kaigo/fukushi/annai/gaishutsu/kotsu/riyoken.html","topic":"welfare-taxi"}'::jsonb, 'seirei:kanagawa-yokohama-welfare-taxi:a2FuYWdhd2EteW9rb2hhbWEtd2VsZmFyZS10YXhpfGFjY3NTcTBYZFMveDVZRENJVlRlTFJRRA==' from public.support_programs sp where sp.slug='kanagawa-yokohama-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kumamoto' and m.slug = 'kumamoto'), 'kumamoto-kumamoto-welfare-taxi', '障がい者福祉タクシー利用券・障がい者燃料費助成券', '熊本市では、重度の障がいのある方の生活拡大・社会参加の促進を図るため、市が契約するタクシーを利用できる「障がい者福祉タクシー利用券」を交付しています。対象は、市町村民税非課税または生活保護受給世帯のうち、身体障がい者手帳1級・2級、療育手帳A1・A2、精神障がい者保健福祉手帳1級・2級のいずれかに該当する方とされています。通常タクシーは1回500円助成・40枚綴り、患者等輸送タクシーは車両サイズに応じて600〜1,400円助成・35枚綴りとされています。あわせて、1人で外出できない重度の知的障がい（療育手帳A1・A2）のある方で、福祉タクシー利用券やおでかけICカードの交付を受けていない方等を対象に、家族等が運転する自家用車の燃料費を助成する「障がい者燃料費助成券」（年間12,000円分・1,000円券12枚綴り）も設けられています。両制度は対象者の要件が異なり、燃料費助成券は福祉タクシー利用券等を受けていない方に限られる仕組みとされています。', '重い障がいのある方がタクシーで出かけるときに使える「福祉タクシー利用券」を熊本市がお渡しする制度です。1回500円ぶんの割引券が40枚もらえます。また、1人で外出が難しい重い知的障がいの方で、この利用券をもらっていない方には、家族の車のガソリン代を助成する「燃料費助成券」（年間12,000円ぶん）もあります。', 'service', '熊本市に住民登録があり居住する方のうち、市町村民税が非課税または生活保護を受給している世帯で、身体障がい者手帳1級・2級、療育手帳A1・A2、精神障がい者保健福祉手帳1級・2級のいずれかを所持する方が福祉タクシー利用券の対象となる可能性があります。燃料費助成券は、療育手帳A1・A2を所持し1人で外出できない重度の知的障がいのある方で、市町村民税非課税（本人）、おでかけICカード①や福祉タクシー利用券の交付を受けていない、障がい者支援施設に未入所、医療機関に未入院等の条件をすべて満たす方が対象となる可能性があります。', '福祉タクシー利用券（通常タクシー）：1回の乗車につき500円助成、40枚綴りで交付。患者等輸送タクシー利用券：1回の乗車につき小型600円・中型1,100円・大型1,400円のいずれかを助成、35枚綴りで交付。燃料費助成券：年間1,000円券12枚綴り（12,000円分）。', NULL, '居住区の区役所福祉課または総合出張所窓口で申請するとされています。申請書は窓口のほか、熊本市公式サイトからPDF・Word形式でダウンロード可能とされています。', '福祉タクシー利用券：対象となる身体障がい者手帳・療育手帳・精神障がい者保健福祉手帳（代理申請の場合は代理人の本人確認書類も必要）。燃料費助成券：療育手帳、対象者と同居する家族等が所有（使用）する自家用車の車検証の写し、申請者の身分証明書。', FALSE, '熊本市 各区役所福祉課（障がい福祉担当）', '096-328-2313', NULL, 'https://www.city.kumamoto.jp/kiji00354/index.html', '障がい者福祉タクシー利用券 / 熊本市公式サイト', '2026-07-01', 'medium', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable', '所得要件の詳細', '燃料費助成券とおでかけICカード②等その他移動支援施策との関係']::text[], '本情報は熊本市公式サイト（確認日時点）に基づく概要です。対象要件・交付額・年間限度額・燃料費助成額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず熊本市の公式ページまたは担当窓口にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
