insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'kyoto' and m.slug = 'kyoto'), 'kyoto-kyoto-welfare-taxi', '京都市重度障害者タクシー料金助成事業（重度障害者タクシー利用券の交付）', '京都市では、重度の障害のある方の社会参加を支えるため、市内で登録された対象タクシー事業者において利用できる「重度障害者タクシー利用券」を交付しています。利用券は1枚500円で、申請月から年度末までの月数に応じて1か月あたり4枚が交付され、年間最大48枚となります。乗車料金に応じて1回の乗車で最大4枚まで使用できるとされています。すでに福祉乗車証や敬老乗車証の交付を受けている方は対象外です。令和8年度分からは、継続利用の申請方法が郵送またはオンライン（二次元コード）に変更され、交付も郵送で行われるようになったとされています。京都市の公式ページでは、この制度に代わる自動車燃料費助成についての言及は確認できませんでした。', '重い障害のある方が、京都市に登録されたタクシーに乗るときに使える「タクシー利用券」（1枚500円）を、月4枚ずつ、最大で年間48枚もらえる制度です。すでにバスや地下鉄の福祉乗車証をお持ちの方は対象外です。', 'service', '京都市内に住所があり、身体障害者手帳1級または2級、療育手帳（京都市）A判定、精神障害者保健福祉手帳1級のいずれかをお持ちの方が対象となる可能性があります。ただし、すでに福祉乗車証または敬老乗車証の交付を受けている方は対象外とされています。', '1枚500円のタクシー利用券を、申請月から年度末までの月数×4枚（1か月あたり4枚）交付、年間最大48枚。1回の乗車での利用可能枚数は乗車料金に応じて1〜4枚とされています。', '随時受付とみられますが、交付枚数は申請月から年度末までの月数に応じて決まるため、申請が遅いほど交付枚数は少なくなります。継続利用については毎年度、更新手続きが必要とされています。', '新規申請は「申請書第1号」、継続申請は「申請書第2号」を用いて、各区役所・支所保健福祉センター障害保健福祉課、または京都市障害保健福祉事務センターへ申請します。令和8年度の継続利用手続きでは、郵送またはオンラインフォームでの申請が案内されています。', '申請書（新規申請書第1号または継続申請書第2号）、身体障害者手帳・療育手帳・精神障害者保健福祉手帳のいずれか。', TRUE, '京都市保健福祉局障害保健福祉推進室（継続利用に関しては京都市障害保健福祉事務センター）', '075-222-4161', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000349020.html', 'https://www.city.kyoto.lg.jp/hokenfukushi/page/0000201816.html', '京都市：京都市重度障害者タクシー料金助成事業実施要綱', '2026-07-01', 'high', ARRAY['requiredDocumentsText', 'applicationDeadlineText']::text[], '本情報は京都市公式サイト（実施要綱および令和8年度案内ページ、確認日時点）に基づく概要です。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず京都市の公式ページまたは各区役所・支所保健福祉センター障害保健福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
