insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"kyoto-kyoto-welfare-taxi","status":"published","title":"京都市重度障害者タクシー料金助成事業（重度障害者タクシー利用券の交付）","officialUrl":"https://www.city.kyoto.lg.jp/hokenfukushi/page/0000201816.html","topic":"welfare-taxi"}'::jsonb, 'seirei:kyoto-kyoto-welfare-taxi:a3lvdG8ta3lvdG8td2VsZmFyZS10YXhpfEMvMnN5SkdYNmJzNUJNTUZqM2U1MytSSg==' from public.support_programs sp where sp.slug='kyoto-kyoto-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'miyagi' and m.slug = 'sendai'), 'miyagi-sendai-welfare-taxi', '福祉タクシー利用券・自家用車燃料費助成券の交付', '仙台市では、重度の障害のある方等の外出・通院を支えるため、市が契約するタクシー事業者で利用できる福祉タクシー利用券を交付しています。あわせて、自動車を利用する方を対象とした自家用車燃料費助成券も設けられており、対象要件を満たす方は「ふれあい乗車証」（バス・地下鉄無料乗車証）を含めた3つの制度のうちいずれか1つを選択して利用する仕組みとされています。福祉タクシー利用券は1枚500円券を、自家用車燃料費助成券は1枚1,000円券を、いずれも年間30,000円相当まで交付するとされていますが、申請月により交付枚数が減額される場合があるとされています。対象は身体障害者手帳・療育手帳・精神障害者保健福祉手帳を所持し、障害の種類・等級が一定の基準を満たす方で、所得制限が設けられている可能性があります。介護保険制度の「介護タクシー」（通院等乗降介助）とは別の、障害福祉分野の移動支援制度です。', '障害のある方がタクシーで出かけるときに使える「福祉タクシー利用券」を、仙台市がお渡しする制度です。車を使う方には、かわりにガソリン代を助成する「自家用車燃料費助成券」もあり、バスや地下鉄が無料になる「ふれあい乗車証」とあわせて、どれか1つを選んで利用します。', 'service', '身体障害者手帳をお持ちの方（1級は視覚・上肢・下肢・体幹・移動機能・内部機能の障害、2級は視覚・下肢・体幹・移動機能・内部機能の障害、3・4級は下肢・体幹・移動機能の障害で車椅子を使用している方または在宅酸素療法を行っている方などが対象となる可能性があります）、療育手帳A判定をお持ちの方、精神障害者保健福祉手帳1級または2級をお持ちの方が対象となる可能性があります。所得制限が設けられている可能性があり、施設入所者は自家用車燃料費助成券の対象外となる場合があるとされています。', '福祉タクシー利用券は1枚500円の利用券を年60枚（年間30,000円相当）、自家用車燃料費助成券は1枚1,000円の助成券を年30枚（年間30,000円相当）交付するとされています。申請した月により交付枚数が減額される場合があるとされています。', '利用期間は10月1日から翌年9月30日までの1年間とされ、毎年更新が必要とされています（更新案内は例年9月上旬に送付されるとされています）。', 'お住まいの区の区役所障害高齢課、宮城総合支所障害高齢課、または秋保総合支所保健福祉課の窓口で申請するとされています。オンライン申請についての記載は公式ページ上で確認できませんでした。', '身体障害者手帳・療育手帳・精神障害者保健福祉手帳等（該当するもの）、所得確認書類が必要とされています。自家用車燃料費助成券の申請には、これに加えて車検証・運転免許証が必要とされています。', FALSE, '仙台市健康福祉局障害企画課 助成給付係（または、お住まいの区の区役所・総合支所 障害高齢課）', '022-214-6135', 'https://www.city.sendai.jp/servicekanri/kurashi/kenkotofukushi/shogai/shakaisanka/waribiki/kofu.html', 'https://www.city.sendai.jp/servicekanri/kurashi/kenkotofukushi/shogai/shakaisanka/waribiki/kofu.html', '福祉タクシー利用券の交付｜仙台市', '2026-07-01', 'medium', ARRAY['所得制限の具体的な金額基準', 'オンライン申請の可否', '70歳以上の場合の敬老乗車証との選択関係の詳細', '施設入所者に関する自家用車燃料費助成券の適用除外の詳細条件']::text[], '本情報は仙台市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず仙台市の公式ページまたは担当窓口にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
