insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'niigata' and m.slug = 'niigata'), 'niigata-niigata-welfare-taxi', '福祉タクシー利用助成・自動車燃料費助成（新潟市）', '新潟市では、重度の障害のある方等の外出を支えるため、市と協定を結んだタクシー事業者で利用できる福祉タクシー利用助成券を交付しています。年間52枚（10月以降の申請は26枚）が交付され、乗車料金に応じて使用できる枚数が変わるとされています。あわせて、自動車を利用する方を対象とした自動車燃料費助成（年間上限10,000円、10月以降取得は5,000円）も設けられており、公式ページでは相互に「もう一方の交付を受けている場合は受給できない」と明記されており、いずれか一方を選択して利用する制度とされています。', '重い障害のある方が、新潟市と提携したタクシーに乗るときに使える「福祉タクシー利用助成券」を市がお渡しする制度です。車を使う方には、かわりにガソリン代を年間最大1万円まで助成する制度もあり、どちらか一方を選んで利用します。', 'service', '身体障がい者手帳1級・2級、身体障がい者手帳3級の一部（下肢・体幹・脳原性運動・内部障がい）、療育手帳A、精神障がい者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります。', '福祉タクシー利用助成：年間52枚（10月以降申請は26枚）、乗車料金500円以上1,000円未満は1枚、1,000円以上1,500円未満は2枚、1,500円以上は3枚を使用可能。自動車燃料費助成：年間上限10,000円（4月〜翌年3月末）、10月以降取得の場合は5,000円まで。', '自動車燃料費助成は当該年度の3月31日までに窓口手続きが必要とされています。', '各区役所健康福祉課障がい福祉係、各出張所（身体障がい者手帳・療育手帳所持者）、各地域保健福祉センター（精神障がい者保健福祉手帳所持者）の窓口で申請。', '福祉タクシー利用助成：該当する障がい者手帳。自動車燃料費助成：障がい者手帳、助成対象期間内の領収書、自動車検査証、銀行口座番号が分かる書類。', FALSE, '福祉部障がい福祉課在宅福祉係', '025-226-1239', NULL, 'https://www.city.niigata.lg.jp/iryo/shofuku/seikatsu/koutsuu/taxi1.html', '福祉タクシー利用助成　新潟市', '2026-07-01', 'high', ARRAY['applicationDeadlineText（福祉タクシー利用助成の具体的な申請締切）']::text[], '本情報は新潟市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成金額・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず新潟市の公式ページまたは担当窓口（福祉部障がい福祉課、各区役所健康福祉課）にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
