insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'okayama' and m.slug = 'okayama'), 'okayama-okayama-welfare-taxi', '福祉タクシー利用券', '岡山市では、重度の障害のある方の社会参加を促進するため、市内で利用できる福祉タクシー利用券を交付しています。対象は身体障害者手帳1・2級または療育手帳A所持で所得税非課税世帯の方とされ、月4枚交付（通院頻度が高い場合は8枚/12枚）、1枚あたり630円まで助成する制度（令和7年4月1日施行の要綱）です。岡山市には「自動車燃料費助成」という名称の制度は見当たらず、代わりに「自動車改造費助成」「運転免許取得費助成」という別制度が存在し、千代田区のような選択制ではありません。', '重い障害のある方がタクシーを使うときに使える「福祉タクシー利用券」を岡山市がお渡しする制度です。月4枚（通院が多い方は8枚か12枚）、1枚630円分まで使えます。', 'service', '岡山市内に住み、身体障害者手帳1・2級または療育手帳Aを所持し、所得税非課税世帯の方が対象となる可能性があります。詳細な要件は公式ページまたは窓口で確認してください。', '月4枚交付（通院頻度が高い場合は8枚または12枚）、1枚あたり630円まで助成（令和7年4月1日施行の要綱に基づく）。', NULL, '岡山市の窓口で申請するとされています。詳細は公式ページまたは窓口で確認してください。', '身体障害者手帳または療育手帳、所得税非課税を確認できる書類。', FALSE, '岡山市保健福祉局障害福祉課', '086-803-1231', NULL, 'https://www.city.okayama.jp/kurashi/0000058357.html', '障害／福祉タクシー | 岡山市', '2026-07-01', 'high', ARRAY['applicationDeadlineText', 'requiredDocumentsText（詳細一覧）']::text[], '本情報は岡山市公式サイト（確認日時点、要綱令和7年4月1日施行）に基づく概要です。対象要件・交付額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず岡山市の公式ページまたは担当窓口にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
