insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'osaka'), 'osaka-osaka-welfare-taxi', '大阪市重度障がい者等タクシー料金給付事業（タクシー給付券の交付）', '大阪市では、身体障がい者・知的障がい者等の自立と社会参加を促すため、外出が困難な重度障がい者等を対象に、タクシー利用料金の一部を給付する「重度障がい者等タクシー給付券」を交付しています。給付券は通常タクシー用が1枚500円、リフト付タクシー用が1枚2,000円を上限とし、乗車料金の一部または全部に充当できます。1年間に交付される給付券は1冊32枚を基本とし、最大3冊（96枚）まで交付されるとされています。対象は市営交通機関の無料乗車証の交付資格を有する重度の障がいのある方とされています。大阪市公式サイト内では、この制度に代わる自動車燃料費助成についての情報は確認できませんでした。', '重い障がいのある方が、タクシーに乗るときの料金の一部にあてられる「タクシー給付券」（1枚500円、リフト付は1枚2,000円）を、区の窓口でもらえる制度です。年間で最大96枚（32枚の冊子3冊分）まで交付されるとされています。', 'service', '身体障害者手帳をお持ちの方で、下肢機能障がい・体幹機能障がい・乳幼児期以前の非進行性の脳病変による運動機能障がいが1級から3級の方、内部障がい1級の方などが対象となる可能性があります。療育手帳ではA判定またはB1判定の方も対象とされる情報が確認できました。', '通常タクシー給付券：1枚500円を上限。リフト付タクシー給付券：1枚2,000円を上限。年間交付枚数は1冊32枚を基本とし、最大3冊（96枚）まで交付されるとされています（2冊目以降は郵送等での追加申請が必要）。', '随時受付とみられます。2冊目以降の追加交付は郵送・宅配便等での申請が可能で、区保健福祉センターでの受理から10日以内に発送されるとされています。', 'お住まいの区保健福祉センター福祉業務担当（保健福祉課）で、身体障がい者手帳または療育手帳を持参して申請します。2冊目以降は郵送または宅配便でも申請可能とされています。', '身体障がい者手帳または療育手帳。その他の必要書類は区保健福祉センターにご確認ください。', FALSE, '福祉局 障がい者施策部 障がい福祉課', '06-6208-7994', 'https://www.city.osaka.lg.jp/fukushi/page/0000007578.html', 'https://www.city.osaka.lg.jp/fukushi/page/0000007578.html', '重度障がい者等タクシー料金給付 - 大阪市', '2026-07-01', 'medium', ARRAY['targetPeople（療育手帳・精神障害者保健福祉手帳の対象範囲の全体像）', 'onlineApplicationAvailable', 'requiredDocumentsText']::text[], '本情報は大阪市公式サイト（確認日時点）に基づく概要です。公式ページの一部はアクセス時にエラーとなり、実施要綱PDFもテキスト抽出ができなかったため、大阪市総合コールセンターのFAQページおよび検索結果の複数一致情報を補助的に用いて内容を確認しました。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず大阪市の公式ページまたはお住まいの区保健福祉センターにご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
