insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'osaka' and m.slug = 'sakai'), 'osaka-sakai-welfare-taxi', '堺市重度障害者福祉タクシー利用料金助成', '堺市では、重度の障害のある方の社会参加を促すため、一般タクシーまたは福祉タクシー（リフト付等）を利用した際の料金の一部を助成する「堺市重度障害者福祉タクシー利用料金助成」を実施しています。一般タクシーは1回の乗車につき500円、福祉タクシーは1回につき1,000円が助成されます。交付される利用券の枚数は申請月によって異なり、4月申請の場合は年間26枚で、以降1か月ごとに2枚ずつ減少し、翌年3月申請では4枚となります。対象は身体障害者手帳1・2級（視覚・下肢・体幹・心臓・腎臓・呼吸器等の機能障害、および特定の重複障害）または療育手帳で重度と認定された方とされています。堺市の公式情報の範囲では、これに代わる自動車燃料費助成の制度は確認できませんでした。', '重い障害のある方が、タクシー（普通のタクシーは1回500円、車いすで乗れる福祉タクシーは1回1,000円）を利用するときの料金の一部を助成してもらえる制度です。もらえる枚数は申請する月によって変わり、年度の初め（4月）に申請すると最も多くもらえます。', 'service', '堺市内に住所があり、身体障害者手帳1級または2級（視覚・下肢・体幹・心臓・腎臓・呼吸器・ぼうこう・直腸・小腸・肝臓・免疫機能障害等、および上下肢機能障害の組み合わせ・四肢機能障害・脳原性移動機能障害等）をお持ちの方、または療育手帳で重度（A判定）と認定された方が対象となる可能性があります。', '一般タクシー：1回の乗車につき500円。福祉タクシー：1回の乗車につき1,000円。交付枚数は申請月により異なり、4月申請で年間最大26枚、以降毎月2枚ずつ減少（3月申請で4枚）。継続申請者は26枚とされています。', '随時受付ですが、交付枚数が申請月によって変動するため、早めの申請ほど多く受け取れるとされています。', 'お住まいの区役所地域福祉課で申請します。新規は「堺市重度障害者福祉タクシー利用券交付申請書」、継続の場合は「継続希望申請書」を使用するとされています。堺市電子申請システムでも申請可能ですが、その場合は別途郵送料が必要とされています。', '申請書、身体障害者手帳または療育手帳。', TRUE, '堺市 障害福祉部 障害支援課', '072-228-7411', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/shogaifukushi/syakai_sanka/seikatsu/71806820230314113715928.html', 'https://www.city.sakai.lg.jp/kenko/fukushikaigo/shogaifukushi/syakai_sanka/seikatsu/71806820230314113715928.html', '堺市重度障害者福祉タクシー利用料金助成について 堺市', '2026-07-01', 'high', ARRAY['targetPeople（精神障害者保健福祉手帳の対象有無）', 'requiredDocumentsText']::text[], '本情報は堺市公式サイト（制度案内ページおよび助成要綱、確認日時点）に基づく概要です。対象要件・交付枚数・年間限度額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず堺市の公式ページまたはお住まいの区役所地域福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
