insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"osaka-sakai-welfare-taxi","status":"published","title":"堺市重度障害者福祉タクシー利用料金助成","officialUrl":"https://www.city.sakai.lg.jp/kenko/fukushikaigo/shogaifukushi/syakai_sanka/seikatsu/71806820230314113715928.html","topic":"welfare-taxi"}'::jsonb, 'seirei:osaka-sakai-welfare-taxi:b3Nha2Etc2FrYWktd2VsZmFyZS10YXhpfGQvUUsrSDNjL3YzZTRaNjJORThWTkF1ZQ==' from public.support_programs sp where sp.slug='osaka-sakai-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'saitama' and m.slug = 'saitama'), 'saitama-saitama-welfare-taxi', '福祉タクシー利用料金の助成・自動車燃料費の助成（さいたま市）', 'さいたま市では、障害のある方の生活圏の拡大と社会参加の促進を図るため、埼玉県またはさいたま市と協定を締結しているタクシー会社で利用できる「福祉タクシー利用料金の助成」（タクシー券の交付）を行っています。あわせて、自家用車を移動手段とする方向けに「自動車燃料費の助成」も設けられており、いずれか一方を選択して利用する制度とされています（同一年度内に両方を受けることはできないとされています）。対象は、市内在住で前年度の本人の市町村民税が非課税の方のうち、身体障害者手帳1・2級及び下肢・体幹機能障害3級、療育手帳マルA・A、精神障害者保健福祉手帳1級、または精神障害者保健福祉手帳2級・身体障害者手帳3級・療育手帳Bのうち2つ以上を併有する方などとされています。タクシー券は券1枚につき初乗運賃相当額（上限500円）を助成し、年度54枚（下肢・体幹機能障害3級は年度36枚）が交付されるとされています。自動車燃料費助成は1リットルにつき50円、年度10,000円（200リットル相当）を限度に助成されるとされています。この制度は障害福祉分野の移動支援策であり、介護保険制度における「介護タクシー」とは異なる制度です。', '障害のある方がタクシーで出かけるときに使える「福祉タクシー券」を、さいたま市がお渡しする制度です。自家用車を使う方には、代わりにガソリン代の一部を助成する制度もあり、どちらか一方を選んで利用します。対象となるかどうかや金額の詳しいことは、お住まいの区の区役所支援課で確認できます。', 'service', 'さいたま市内に住んでいて、前年度の本人の市町村民税が非課税の方のうち、次のいずれかに該当する方が対象となる可能性があります。(1) 身体障害者手帳1級・2級、または下肢・体幹機能障害3級の方、(2) 療育手帳マルA・Aの方、(3) 精神障害者保健福祉手帳1級の方、(4) 精神障害者保健福祉手帳2級・身体障害者手帳3級・療育手帳Bのうち、いずれか2つ以上の交付を受けている方。具体的な該当有無は区役所支援課での確認が必要です。', '【福祉タクシー利用料金の助成】券1枚につき、タクシー初乗運賃相当額（上限500円）を助成。乗車料金が初乗運賃相当額の2倍以上の場合は2枚使用可能。交付枚数は、身体障害者手帳1・2級、療育手帳マルA・A、精神障害者保健福祉手帳1級の方等は年度54枚、下肢・体幹機能障害3級の方は年度36枚。【自動車燃料費の助成】1リットルにつき50円、年度10,000円（200リットル相当）を限度に助成。いずれの制度も同一年度内に併用はできないとされています。', NULL, '各区役所支援課（障害福祉係）の窓口で申請します。福祉タクシー利用料金の助成は障害者手帳等と印鑑を持参して申請するとされています。自動車燃料費の助成は、手帳、運転免許証、自動車検査証、印鑑、通帳等の持参が必要とされています。', '【福祉タクシー利用料金の助成】身体障害者手帳・療育手帳・精神障害者保健福祉手帳のいずれか該当するもの、印鑑等。【自動車燃料費の助成】障害者手帳、運転免許証、自動車検査証、印鑑、預金通帳等が必要とされています。', FALSE, 'さいたま市福祉局障害福祉部障害福祉課 地域生活支援係（申請窓口は各区役所支援課 障害福祉係）', '048-829-1255', 'https://www.city.saitama.lg.jp/002/003/004/003/003/p001344.html', 'https://www.city.saitama.lg.jp/002/003/004/003/003/p001344.html', 'さいたま市／福祉タクシー利用料金の助成', '2026-07-01', 'medium', ARRAY['タクシー初乗運賃相当額の具体的な円額', '必要書類の完全なリスト', '各区役所支援課の個別電話番号', '年度途中申請時の按分計算の具体的な方法']::text[], '本情報はさいたま市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成上限額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ずさいたま市の公式ページまたはお住まいの区の区役所支援課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
