insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"saitama-saitama-welfare-taxi","status":"published","title":"福祉タクシー利用料金の助成・自動車燃料費の助成（さいたま市）","officialUrl":"https://www.city.saitama.lg.jp/002/003/004/003/003/p001344.html","topic":"welfare-taxi"}'::jsonb, 'seirei:saitama-saitama-welfare-taxi:c2FpdGFtYS1zYWl0YW1hLXdlbGZhcmUtdGF4aXxJTmdCOHdlaGJwYllQR3VXWHpRWHYzTm4=' from public.support_programs sp where sp.slug='saitama-saitama-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'hamamatsu'), 'shizuoka-hamamatsu-welfare-taxi', '障がいのある人への外出支援助成券（バス・タクシー利用券等）の交付', '浜松市では、障害のある方等の外出を支えるため、年1回、6種類の助成券（遠鉄バス・電車共通カード、タクシー利用券、天竜浜名湖鉄道乗車券引換券、地域バス乗車券、鍼灸マッサージ券、ガソリン券〔限定地域〕）のうちいずれか1種類、7,000円分を選択して交付する外出支援助成券制度があります。あわせて、視覚障害1級・2級、肢体不自由1級等の重度の障害のある方には、外出支援助成券とは別に「外出応援タクシー利用券」が交付される場合があるとされています。ガソリン券は選択肢の一つとして用意されているものの利用できる地域が限定されているとされ、また複数の制度が並存し条件によって適用が異なるため、本サイトでは正確な制度名・金額・地域限定の詳細について公式ページでの確認を強く推奨します。', '障害のある方が外出しやすいように、浜松市がバス・タクシー・ガソリン代などの中から1つを選んで使える助成券（7,000円分）をお渡しする制度です。視覚や肢体に重い障害のある方には、別のタクシー券が上乗せで交付されることがあるとされています。', 'service', '身体障害者手帳1級〜4級、療育手帳A1〜B1、精神障害者保健福祉手帳1級〜2級のいずれかを所持し、毎年度4月1日から申請時まで継続して市内に住所を有する方が対象となる可能性があります。自動車税の減免を受けている場合は対象外とされています。', '外出支援助成券：年1回、6種類のうちいずれか1種類、7,000円分。外出応援タクシー利用券（視覚障害1級・2級、肢体不自由1級等）：金額の詳細は公式ページで確認が必要です。', NULL, '特定の交付日程・会場での受付、または福祉事業所の社会福祉課での対応とされています。', '申請書、認め印、障害者手帳、該当者はナイスパスカード（ピンク色）。', FALSE, '健康福祉部障害者政策課・障害者支援課', '053-457-2212', NULL, 'https://www.city.hamamatsu.shizuoka.jp/syoghuku/welfare/obstacle/contents/09basutaxi.html', '障がいのある人への外出支援助成券（バス・タクシー利用券等）の交付／浜松市', '2026-07-01', 'medium', ARRAY['外出応援タクシー利用券の正確な金額・対象要件の詳細', 'ガソリン券が利用できる「限定地域」の範囲', 'applicationDeadlineText', '外出支援助成券と外出応援タクシー利用券の併給関係の詳細']::text[], '本情報は浜松市公式サイト（確認日時点）に基づく概要です。浜松市には外出支援助成券・外出応援タクシー利用券・福祉タクシー運賃助成（電動車いす使用者向け）等、複数の関連制度が並存しており、本サイトの記載はその一部を要約したものです。対象要件・交付額・年間限度額・地域限定の詳細などは変更される可能性があり、受給を確約するものではありません。対象可否や最新の取扱いは必ず浜松市の公式ページまたは担当窓口（障害者政策課・障害者支援課）にご確認ください。', 'review', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
