insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"shizuoka-hamamatsu-welfare-taxi","status":"review","title":"障がいのある人への外出支援助成券（バス・タクシー利用券等）の交付","officialUrl":"https://www.city.hamamatsu.shizuoka.jp/syoghuku/welfare/obstacle/contents/09basutaxi.html","topic":"welfare-taxi"}'::jsonb, 'seirei:shizuoka-hamamatsu-welfare-taxi:c2hpenVva2EtaGFtYW1hdHN1LXdlbGZhcmUtdGF4aXxnejA5QXZKS1IyVTI0Vk1nUmFnSWlXMXM=' from public.support_programs sp where sp.slug='shizuoka-hamamatsu-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'shizuoka' and m.slug = 'shizuoka'), 'shizuoka-shizuoka-welfare-taxi', '静岡市重度心身障害者等タクシー利用料金助成（福祉タクシー利用券）', '静岡市では、在宅の重度の障害のある方等の外出を支えるため、市と協定を結んだタクシー事業者で利用できるタクシー利用券を交付しています。重度心身障害者・精神障害者ともに年24枚（1枚550円）、車いす用タクシー券は条件を満たす方に年48枚（1枚500円）が交付されるとされています。静岡市の公式サイトを確認した範囲では、自動車を利用する方向けの燃料費助成に相当する制度は見当たらず、かわりに自動車改造費補助・自動車運転免許取得費補助が実施されているとみられます。また、令和7年度からは精神障害者保健福祉手帳1級の方も希望によりタクシー券の対象に加わったとされています。', '重い障害のある方が、静岡市と提携したタクシーに乗るときに使える「タクシー利用券」を市がお渡しする制度です。年間24枚（1枚550円）が目安とされ、オンラインで申し込みができる場合もあります。', 'service', '身体障害者手帳1級・2級（聴覚・音声機能・言語機能・そしゃく機能障害を除く）、療育手帳A、精神障害者保健福祉手帳1級のいずれかに該当する方が対象となる可能性があります。社会福祉施設に入所中の方や3か月以上の長期入院をされている方、自動車税・軽自動車税の減免を受けている方は対象外とされています。', '重度心身障害者・精神障害者：年24枚（1枚550円、年間最大13,200円相当）。車いす用タクシー券（下肢または体幹3級以上等の条件）：年48枚（1枚500円）。', NULL, '「重度心身障害者タクシー利用券交付申請書」を市長に提出するほか、区ごとのオンライン申請フォームでの申請も案内されています。', '身体障害者手帳、療育手帳、または精神障害者保健福祉手帳の提示。', TRUE, '障害者支援推進課在宅支援係（精神障害者は精神保健福祉課企画係）', '054-221-1587', 'https://logoform.jp/form/79j2/aoi', 'https://www.city.shizuoka.lg.jp/youkou/s5498/s011502.html', '静岡市重度心身障害者等タクシー利用料金助成要綱：静岡市公式ホームページ', '2026-07-01', 'medium', ARRAY['applicationDeadlineText', 'requiredDocumentsText', '精神障害者向け令和7年度からの取扱いの詳細']::text[], '本情報は静岡市公式サイト（確認日時点）に基づく概要です。対象要件・交付枚数・助成額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず静岡市の公式ページまたは担当窓口（障害者支援推進課、各区の障害者支援課）にご確認ください。', 'published', now(), now()) on conflict (slug) do update set slug=excluded.slug, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
