insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'seirei welfare-taxi import', '{"slug":"shizuoka-shizuoka-welfare-taxi","status":"published","title":"静岡市重度心身障害者等タクシー利用料金助成（福祉タクシー利用券）","officialUrl":"https://www.city.shizuoka.lg.jp/youkou/s5498/s011502.html","topic":"welfare-taxi"}'::jsonb, 'seirei:shizuoka-shizuoka-welfare-taxi:c2hpenVva2Etc2hpenVva2Etd2VsZmFyZS10YXhpfFVTc2lyb09VNEpRSzBIdTlpVDg4dE91Mg==' from public.support_programs sp where sp.slug='shizuoka-shizuoka-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.nagoya.jp/kenkofukushi/shougaisha/1016573/1016575.html', 'WebSearchで「名古屋市 福祉タクシー券 障害者」「名古屋市 障害者 自動車燃料費助成」を検索し、公式ドメインおよび同市の情報システムの複数ページをWebFetchで実際に取得・比較した。制度自体は明確に確認できたが、年間交付枚数の上限について情報源間で相違があり、確認日時点で一つに確定できなかったためuncertainFieldsとし、publishStatusをreviewとした。名古屋市には自動車燃料費助成の制度は見当たらず、介護保険の介護タクシーとは別の障害福祉分野の移動支援であることを確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='aichi' and m.slug='nagoya' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.chiba.jp/hokenfukushi/koreishogai/jiritsu/hukushitakusi.html', 'WebSearchで「千葉市 福祉タクシー券 障害者」「千葉市 障害者 自動車燃料費助成」を検索し、city.chiba.jpドメインの公式ページを特定。メイン案内ページとFAQページの2つを実際にWebFetchで取得し本文を確認した。選択制で両方受給不可であることを確認した。本制度は障害福祉分野の制度であり、介護保険制度における「介護タクシー」とは異なる別制度であることをメインページの記載内容から確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='chiba' and m.slug='chiba' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.fukuoka.lg.jp/fukushi/syougaisyashien/health/taxi_8_1.html', '「福岡市 福祉タクシー券 障害者」「福岡市 障害者 自動車燃料費助成」等でWebSearchし、公式ドメインの「令和8年度福祉タクシー料金助成事業について」ページをWebFetchで本文取得。関連ページで『福祉タクシー利用券の交付を受けた方は、福祉乗車券、高齢者乗車券、障がい者移送サービスにおいて、タクシー助成券を選択することはできません』という一次ソース記載を確認。自動車燃料費助成は独立制度として発見できず、他の乗車券系制度との選択制であると判定した。介護保険の介護タクシーとは異なる障害福祉分野の制度であることも確認済み。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='fukuoka' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kitakyushu.lg.jp/contents/17600232.html', 'WebSearchで「北九州市 福祉タクシー券」「北九州市 重度障害者タクシー利用券」「北九州市 障害者 自動車燃料費助成」等を検索し、公式発表ページを発見し、そこからリンクされるPDF（15-1．外出の利便）をWebFetchで取得後、Readツールで本文全文抽出。93頁「重度障害者に対するタクシー運賃の一部助成」の対象者・助成回数・利用方法・窓口を本文から直接確認。同章内には自動車燃料費助成に該当する項目は存在しなかったため、北九州市は他自治体と異なりタクシー券のみで燃料費助成の選択制ではないと判断。介護保険の介護タクシーは本調査で参照した公式資料には一切登場せず、障害福祉分野の「移動支援事業」（ガイドヘルパー）とも別の「タクシー運賃の一部助成」であることを本文で区別して確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='fukuoka' and m.slug='kitakyushu' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hiroshima.lg.jp/living/fukushi-kaigo/1014921/1025788/1022075.html', 'WebSearchで「広島市 福祉タクシー券」「広島市 障害者 自動車燃料費助成」を検索し、公式ドメイン内の該当ページをWebFetchで2回取得。関連制度の障害者公共交通機関利用助成ページも併せてWebFetchし、両制度が選択制であることを確認。介護保険の介護タクシーとは別の障害福祉サービスであることを確認済み。自動車燃料費助成に相当する制度は公式サイト内の検索で確認できなかった。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hiroshima' and m.slug='hiroshima' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
