insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.kobe.lg.jp/a40792/kenko/handicap/zaitakufukushi/koutsukikan/s031.html', 'WebSearchで「神戸市 福祉タクシー 障害者 利用券」「神戸市 障害者 自動車燃料費助成」を検索し、公式ドメインの複数ページをすべてWebFetchで実際に取得した。両制度とも「福祉乗車証・敬老優待乗車証・（もう一方の制度）を受けていないこと」が対象要件に明記されており、選択制であることを一次資料で直接確認できた。介護保険の介護タクシーとは別の障害福祉分野の移動支援であることを確認した。5市の中で最も情報の整合性が高く、信頼度をhighとした。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='hyogo' and m.slug='kobe' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
