insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.saitama.lg.jp/002/003/004/003/003/p001344.html', 'WebSearchで「さいたま市 福祉タクシー券 障害者」「さいたま市 障害者 自動車燃料費助成」を検索し、公式ドメイン配下の複数URLを特定した。WebFetchで実際に本文を4ページ取得し、担当課名・区役所連絡先・交付枚数・助成額・選択制であることを本文から直接確認した。介護保険の介護タクシーとは異なる障害福祉分野の制度であることを、対象者の要件と担当部署の記載から確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='saitama' and m.slug='saitama' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.hamamatsu.shizuoka.jp/syoghuku/welfare/obstacle/contents/09basutaxi.html', 'WebSearchで「浜松市 福祉タクシー券 障害者」「浜松市 障害者 自動車燃料費助成」を検索し、公式ドメインcity.hamamatsu.shizuoka.jp配下の複数ページをWebFetchで取得した。浜松市は他4市と異なり、外出支援助成券・外出応援タクシー利用券・福祉タクシー運賃助成という複数の制度が並存する構造であることが判明した。外出応援タクシー利用券の専用ページは概要のみで金額の記載がなく本文で裏付けられなかったため、researchStatusをneeds_reviewとした。介護保険の介護タクシーとは別の障害福祉分野の制度であることは対象者の障害者手帳要件から確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='hamamatsu' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-07-01', 'https://www.city.shizuoka.lg.jp/youkou/s5498/s011502.html', 'WebSearchで「静岡市 福祉タクシー券 障害者」「静岡市 障害者 自動車燃料費助成」を検索し、公式ドメインcity.shizuoka.lg.jp配下の要綱ページと補助・助成制度一覧ページをWebFetchで取得。区ごとのオンライン申請フォームの存在を確認した。「自動車燃料費助成」という名称の制度は見つからず、静岡市は自動車改造費補助・運転免許取得費補助を実施している一方でタクシー利用券のみを移動支援の中心制度としていると判断した。介護保険の介護タクシーとは別の障害福祉分野の制度であることを確認した。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='shizuoka' and m.slug='shizuoka' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
